                <button key={f} className="btn btn-sm" onClick={() => setFilter(f)} style={{
                  background: filter === f
                    ? (f === 'green' ? 'rgba(34,197,94,0.2)' : f === 'yellow' ? 'rgba(234,179,8,0.2)' : f === 'red' ? 'rgba(239,68,68,0.2)' : 'var(--accent)')
