                  color: filter === f
                    ? (f === 'green' ? 'var(--green)' : f === 'yellow' ? 'var(--yellow)' : f === 'red' ? 'var(--red)' : 'white')
                    : 'var(--text-muted)',
                }}>{l}</button>
              ))}
